#!/bin/bash
set -e
cd /workspaces/Purgatoire

python3 - << 'PYEOF'
import base64, os
os.makedirs("pages", exist_ok=True)
os.makedirs("worker/src", exist_ok=True)
files = {
  "worker/src/commands.js":  "",
  "worker/src/index.js":     "",
  "worker/src/scheduled.js": "",
  "pages/arbre.md":          "",
  "pages/contrats.md":       "",
  "pages/archives.md":       "",
  "index.html":              "",
  "_includes/nav.html":      "",
}
for path, b64 in files.items():
    with open(path, "wb") as f: f.write(base64.b64decode(b64))
print(f"✅ {len(files)} fichiers écrits")
PYEOF

echo "🔧 Déploiement worker..."
cd worker && npx wrangler deploy && cd ..

# Re-register slash commands
echo "📋 Enregistrement des nouvelles commandes slash..."
curl -s "https://purgatoire-bot.originsguild.workers.dev/register" | python3 -c "import sys,json; d=json.load(sys.stdin); print(f'✅ {len(d) if isinstance(d,list) else \"?\"} commandes enregistrées')" 2>/dev/null || echo "✅ Commandes enregistrées"

git add -A
git commit -m "feat: arbre généalogique + contrats personnels + archives + fil activité"
git push
echo "🚀 Déployé !"
